mapper.select:
SELECT g.id, c.id AS college_id, c.name AS college_name, g.major_id, m.name AS major_name,
       g.name, g.status, g.created_at, g.updated_at
FROM class_groups g
JOIN majors m ON g.major_id = m.id
JOIN colleges c ON m.college_id = c.id
WHERE c.name = #{collegeName}
  AND m.name = #{majorName}
  AND g.name = #{name}

mapper.update:
UPDATE class_groups
SET major_id = #{majorId},
    name = #{name},
    status = #{status}
WHERE id = #{id}
